// Synthesize the weekly report payload · combines PostHog events +
// Atlas snapshot into one Notion-shaped page for the `weekly` database.
const posthog = $input.first().json || {};
const atlas = $input.last().json || {};

const events = posthog.events || {};
const agents = atlas.agents || {};
const clients = atlas.clients || {};
const workflows = atlas.workflows || {};
const drift = atlas.drift || {};

const weekStart = new Date();
weekStart.setUTCDate(weekStart.getUTCDate() - 7);
const weekStartIso = weekStart.toISOString().slice(0, 10);
const weekEndIso = new Date().toISOString().slice(0, 10);

const summary = [
  `Campaigns started: ${events.campaign_started || 0}`,
  `Campaigns completed: ${events.campaign_completed || 0}`,
  `Onboardings: ${events.cliente_onboarded || 0}`,
  `HITL approvals: ${events.hitl_approved || 0}`,
  `Journey transitions: ${events.journey_transition || 0}`,
  `Active clients: ${clients.active_real || 0}/${clients.total || 0}`,
  `Active agents 30d: ${agents.with_executions_30d || 0}/${agents.total || 0}`,
  `Active workflows: ${workflows.active || 0}/${workflows.total || 0}`,
  `Drift findings: ${drift.findings_count || 0}`,
].join(' · ');

return [{
  json: {
    type: 'weekly',
    payload: {
      Name: { title: [{ text: { content: `Weekly · ${weekStartIso} → ${weekEndIso}` } }] },
      WeekStart: { date: { start: weekStartIso } },
      WeekEnd: { date: { start: weekEndIso } },
      CampaignsStarted: { number: events.campaign_started || 0 },
      CampaignsCompleted: { number: events.campaign_completed || 0 },
      Onboardings: { number: events.cliente_onboarded || 0 },
      HitlApprovals: { number: events.hitl_approved || 0 },
      JourneyTransitions: { number: events.journey_transition || 0 },
      ActiveClients: { number: clients.active_real || 0 },
      TotalClients: { number: clients.total || 0 },
      DriftFindings: { number: drift.findings_count || 0 },
      Summary: { rich_text: [{ text: { content: summary.slice(0, 1900) } }] },
      GeneratedAt: { date: { start: new Date().toISOString() } },
    },
  },
}];

// Telemetry · log the outcome to console for n8n exec history.
// 503 unconfigured is the steady state pre-Notion-database-creation ·
// not an error · just a heads-up.
const body = $input.first().json || {};
const status = body.error ? body.error : 'ok';
const pageId = body.page_id || 'none';
const detail = body.detail || '';
console.log(`[weekly-notion-report] status=${status} page_id=${pageId} detail=${detail}`);
return [{ json: { ok: !body.error, status, page_id: pageId, detail } }];
